function normalizeWebhookBody(body) {
  const b = body ?? {};
  return {
    threadId: b.threadId ?? b.ThreadId ?? '',
    chatHistory: b.chatHistory ?? b.History ?? b.history ?? [],
    taskContext: b.taskContext ?? b.TaskContext ?? null,
    subordinatesList: b.subordinatesList ?? b.SubordinatesList ?? [],
    senderAgentId: b.senderAgentId ?? b.SenderAgentId ?? 'supervisor',
  };
}
const raw = items[0].json.body ?? items[0].json;
const n = normalizeWebhookBody(raw);
const prompt = [
  'You are an AAE supervisor (Scrum Master). Output ONLY JSON after optional GitHub tool use.',
  'Use GitHub tools to document milestones. Never use teamleiter naming.',
  'Schema: {"outcome":"waiting|delegate|done","statusMessage":string|null,"delegations":[{"targetAgentId":"specialist-...","content":"..."}],"approval":{"content":"...","artifacts":[]}||null}',
