const BACKEND_BASE = 'https://ai.neberg.de';
function parseJsonMaybe(text) {
  if (text == null) return null;
  if (typeof text === 'object') return text;
  const raw = String(text).trim();
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1].trim() : raw;
  try { return JSON.parse(candidate); } catch { return null; }
}
function assertNoTeamleiter(id) {
  return !String(id).toLowerCase().includes('teamleiter');
}
function parseSupervisorDecision(agentOutput, threadId, senderAgentId) {
  const obj = parseJsonMaybe(agentOutput);
  if (!obj || !obj.outcome) {
    return { ok: false, error: 'invalid_supervisor_output', userMessage: 'Supervisor returned invalid JSON.' };
  }
  const routeUrl = `${BACKEND_BASE}/api/agents/route-chat-message`;
  if (obj.outcome === 'waiting') {
    return {
      ok: true,
      outcome: 'waiting',
      httpCalls: [{
        url: routeUrl,
        body: {
          threadId,
          senderAgentId,
          targetAgentId: null,
          content: String(obj.statusMessage ?? 'Waiting on subordinates.'),
        },
      }],
    };
  }
  if (obj.outcome === 'delegate') {
    const delegations = Array.isArray(obj.delegations) ? obj.delegations : [];
    if (delegations.length === 0) {
      return { ok: false, error: 'empty_delegations', userMessage: 'Supervisor chose delegate with no targets.' };
    }
    const httpCalls = [];
    for (const d of delegations) {
      if (!d?.targetAgentId || !assertNoTeamleiter(d.targetAgentId)) {
        return { ok: false, error: 'invalid_target', userMessage: 'Supervisor produced invalid targetAgentId.' };
      }
      httpCalls.push({
        url: routeUrl,
        body: {
          threadId,
          senderAgentId,
          targetAgentId: d.targetAgentId,
          content: String(d.content ?? ''),
        },
      });
    }
    return { ok: true, outcome: 'delegate', httpCalls };
  }
  if (obj.outcome === 'done') {
    return {
      ok: true,
      outcome: 'done',
      httpCalls: [{
        url: `${BACKEND_BASE}/api/await-request-approval`,
        body: {
          threadId,
          senderAgentId,
          content: String(obj.approval?.content ?? 'Ready for approval.'),
          artifacts: obj.approval?.artifacts ?? [],
        },
      }],
    };
  }
  return { ok: false, error: 'unknown_outcome', userMessage: `Unknown supervisor outcome: ${obj.outcome}` };
}
function buildFailureRoute({ threadId, senderAgentId, content }) {
  return { threadId, senderAgentId, targetAgentId: 'User', content };
}
const prev = $('Normalize Input').first().json;
const agentItem = items[0].json;
const agentText = agentItem.output ?? agentItem.text ?? agentItem;
const parsed = parseSupervisorDecision(agentText, prev.threadId, prev.senderAgentId);
if (!parsed.ok) {
  return [{
    json: {
      ok: false,
      outcome: 'fail',
      httpCalls: [{
        url: `${BACKEND_BASE}/api/agents/route-chat-message`,
        body: buildFailureRoute({ threadId: prev.threadId, senderAgentId: prev.senderAgentId, content: parsed.userMessage }),
      }],
    },
  }];
}
return [{ json: { ok: true, ...parsed } }];
